hey im working on this embedded c++ project and the heap just keeps growing till it crashes. i think there is a leak somewhere in this loop. can u take a look?

void processData(int count) {
    for (int i = 0; i < count; ++i) {
        DataPacket* packet = new DataPacket();
        packet->id = i;
        packet->payload = new uint8_t[256];

        // do some processing
        doWork(packet);

        if (packet->id % 10 == 0) {
            continue; 
        }

        delete[] packet->payload;
        delete packet;
    }
}

